var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"여, 여러분~ 미하~","JPN":"み、皆さん～ミハ～。","ENG":"H-hi, everyone! It's me, Miya!","TWN":"大、大家好～米哈～"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"안녕하세요. 가은입니다.","JPN":"こんにちは。ユキです。","ENG":"Hello. Gaeun here.","TWN":"大家好，我是嘉恩。"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......짜-잔.","JPN":"……じゃーん。","ENG":"... Tah-dah.","TWN":"……鏘—鏘。"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"하트베리, 오늘의 컨텐츠는 태스크포스 탐방이에요.","JPN":"ハートベリー、今日のテーマはタスクフォースへ行こう！　です。","ENG":"Today, HRT Berry will be touring a TASKFORCE company.","TWN":"愛心莓果，今天要去拜訪特遣勢力喔。"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"미야의 몸치 탈출 특훈은 다음주에 업로드되니 기대해 주세요.","JPN":"ミヤのダンス下手克服を目指した特訓は、来週アップしますのでお楽しみに。","ENG":"The project to teach Miya how to dance will be uploaded next week, so please follow us for that.","TWN":"下週會上傳米婭脫離舞蹈白癡的特訓，敬請期待。"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"우으으...... 아직도 온몸이 쑤셔...... 보미는 춤 얘기만 나오면 엄격해진다니까......","JPN":"うぅ……まだ全身がズキズキする……ボミはダンスのことになると厳しいんだから……","ENG":"Ow... I'm still sore all over. Bomi gets so serious about dancing...","TWN":"嗚嗚嗚……全身都還好痠喔……一談到舞蹈，普美就特別嚴格……"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"오늘 촬영은 코핀 컴퍼니에서 협조해 주셨습니다. 넘버링 라이선스도 받은 곳이라네요.","JPN":"今日の撮影はコフィンカンパニーにご協力いただきました。ナンバリングライセンスも受けた所だそうです。","ENG":"For today's episode, Coffin Company has been kind enough to help us out. They even received a numbered license.","TWN":"今天的拍攝會由科芬公司提供協助，聽說他們是個有編號證書的公司。"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......넘버링 라이선스가 뭐야?","JPN":"……ナンバリングライセンスって何？","ENG":"What's a numbered license?","TWN":"……編號證書？"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"관리국에서 공식적으로 번호가 달린 라이선스를 부여 받은 태스크포스 컴퍼니를 부르는 말이야.","JPN":"管理局から公式にナンバー付きのライセンスを付与されたタスクフォースカンパニーのことだよ。","ENG":"It's an official license for TASKFORCE companies with a registration number authorized by the Administration.","TWN":"就是指從管理局那裡，拿到了正式編號執照的特勤勢力公司。"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"보통은 번호가 없는 공용 라이선스가 발급되는 경우가 많은데,","JPN":"ナンバーがない共用ライセンスを発行するのが普通なんだけど、","ENG":"Usually, companies are issued common licenses without numbering.","TWN":"通常都是發行沒有編號的公共執照……"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"넘버링 라이선스가 있다는 건 단독으로 CSE 3레벨 급의 침식 재난도 해결할 수 있는 태스크포스 컴퍼니라는 뜻이래.","JPN":"ナンバリングライセンスがあるってことは、\\nCSE 3レベルの侵食災害も自力で解決できるタスクフォースカンパニーを意味してるらしいよ。","ENG":"A numbered license means that the TASKFORCE company can independently handle CSE level 3 disasters.","TWN":"但有編號的執照，代表這個特遣勢力公司有能力單獨處理CSE3級的侵蝕災難。"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"역시 미야는 사는 데 몰라도 되는 걸 잘 알아.","JPN":"さすがミヤ、生きるのに必要ない知識に詳しいんだね。","ENG":"You always know so much about stuff nobody needs to know to get by.","TWN":"不愧是米婭，知道這些沒必要知道的冷知識。"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"치, 칭찬 맞지? 그치......?","JPN":"ほ、褒めてるんだよね？そうだよね……？","ENG":"I-I'll take that as a compliment... I guess?","TWN":"這、這是讚美吧？還是不是……？"},"stage":{"bg":"STREET_SPRING","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"여러분, 코핀 컴퍼니 본사에 도착했어요.","JPN":"皆さん、コフィンカンパニーの本社に到着しました。","ENG":"Alright, everyone. We've arrived at the Coffin Company Headquarters.","TWN":"各位，我們已經到達科芬公司的總部了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"와아. 굉장한 규모네요. 뭔지 몰라도 일단 감탄하세요.","JPN":"わあ……すごい規模ですね。わからなくても、とりあえず驚いてください。","ENG":"Whoa. It's huge. Just say woah, whatever it is.","TWN":"哇啊，好驚人的規模啊。就算什麼都不知道，也會不禁讚嘆呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"가은아, 뒤에 있는 이나 언니 코멘트는 안 읽어도 돼......","JPN":"ユキ、後ろにあるメグミさんのコメントは読まなくていいんだよ……","ENG":"Gaeun, you don't have to read Ina's stage directions in the parenthesis...","TWN":"嘉恩，剛剛後面是理娜姐的評論，不用讀出來也沒關係……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"오늘 회사 견학을 마친 다음엔 현업에 종사하는 분들에게 테스트도 받을 예정이에요.","JPN":"今日会社の見学が終わったら、実際に現場で働いていらっしゃる方々からテストを受ける予定です。","ENG":"After the tour today, we'll even take some field tests used in the industry.","TWN":"今天的公司參觀結束後，預定會有現場人員來幫我們做測試。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"몇 등급이 나올지 기대해 주세요.","JPN":"何ランクになるか、期待してくださいね。","ENG":"Let's see what grades we can get.","TWN":"我們會有什麼樣的評價，就請大家好好期待吧。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그, 그래도 다행이야. 오늘 촬영은 왠지 순조로울 거 같네.","JPN":"で、でもほっとした。今日の撮影は順調に進みそう。","ENG":"Thank goodness... I have a feeling today's shooting will go smoothly.","TWN":"不、不過太好了，今天的拍攝不知怎麼很順利呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"난 항상 순조로웠어.","JPN":"私はいつも順調よ。","ENG":"It always went smoothly with me.","TWN":"我一直都很順利。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그래...... 가은이 너야 그렇겠지......","JPN":"ええ……ユキはそうだろうけど……","ENG":"Yeah... I guess you may feel that way...","TWN":"是吧……嘉恩是這麼認為的吧……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"마침 저기 오늘 회사를 안내해 주실 분들이 오고 계시네요. 박수로 환영해 주세요.","JPN":"ちょうどあそこに会社を案内してくださる方々が来ています。拍手でお迎えください。","ENG":"Ah, here come the folks who'll show us around the company. Please welcome them with a round of applause.","TWN":"正好，今天帶我們參觀公司的人到了呢，請大家拍手歡迎。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 하트베리에서 온 분들이시죠?","JPN":"はじめまして。ハートベリーの皆さんですね？","ENG":"Nice to meet you. You're from HRT Berry, aren't you?","TWN":"初次見面，各位是愛心莓果的成員吧？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"전 여러분의 안내를 맡은 김하나 부장이에요. 편하게 하나 씨라고 불러 주세요.","JPN":"私は皆さんを案内いたします、ナカシマ・スズカです。スズカさんって呼んでくださいね。","ENG":"I'm Manager Kim Hana. I'll be showing you around the company today. Please call me Hana.","TWN":"我是帶領大家參觀的金荷娜部長，各位可以叫我金荷娜小姐。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런데 정말 저도 방송에 나오나요? 오늘은 화장이 좀 옅은데 이상해 보이진 않겠죠?","JPN":"ところで、本当に私も放送に映るんですか？　今日は薄化粧なんですが、変に見えませんよね？","ENG":"By the way, am I going to be on screen as well? I didn't put on very much makeup today. I hope I don't look weird or anything.","TWN":"不過我真的也會入鏡嗎？今天我的妝有點淡，會不會有些奇怪？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"괜찮아요. 충분히 두꺼워요.","JPN":"ご心配なく。十分厚化粧ですよ。","ENG":"It’s fine. Your makeup is heavy enough.","TWN":"沒事，已經夠濃了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"무무무물론이죠! 오늘 정말 예쁘세요! 카메라 렌즈가 눈부실 정도로요!","JPN":"ももももちろんです！　本当にお綺麗ですよ！　カメラのレンズが眩しいくらいに！","ENG":"O-o-of course! You look gorgeous today! You're practically glowing for the camera!","TWN":"當當當當當然啦！您今天真的非常漂亮！攝影機的鏡頭都在閃閃發亮！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"미야, 시끄럽게 하면 근무 중인 분들에게 방해돼.","JPN":"ミヤ、そんなに騒いだら勤務中の方々の迷惑になるでしょ。","ENG":"Miya, keep it down. People are trying to work here.","TWN":"米婭，太吵的話會打擾人家工作的。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"흐이잉...... 가은아...... 제발 방송 수위를 지켜 줘......","JPN":"もう……ユキ……お願いだから、放送だってことを忘れないで……","ENG":"Wah... Gaeun... Please watch what you say when we're on camera...","TWN":"嗚嗚……嘉恩啊……拜託妳維持一下直播的品質……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저...... 그런데 저 로봇은 뭐예요, 하나 언니?","JPN":"あの……スズカさん、あのロボットは何ですか？","ENG":"Erm, what's that robot by the way, Hana?","TWN":"呃……話說回來，那邊的機器人是什麼啊，金荷娜姐姐？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"로봇이라니 실례로군.","JPN":"ロボットだなんて、失礼だな。","ENG":"Robot? Don't be rude.","TWN":"居然說我是機器人，太失禮了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이건 최첨단 대인기피용 반자율 원격조작 머시노이드 인터페이스, 머신 갑 로보 Mk.2다!","JPN":"これは最先端の対人忌避用半自律遠隔操作マシンノイドインターフェース、マシーン-甲-ロボMk.2だ！","ENG":"I'm a remote controlled machinoid interface that was developed with state-of-the-art scientific technology, Machine G.A.P. Mk.2!","TWN":"我是最先進的超人氣半自動遠端遙控擬人介面，我超帥-Mk.2是也！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저희 사장님이십니다.","JPN":"弊社の社長です。","ENG":"It's our CEO.","TWN":"這是我們的老闆。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"사, 사장님이라고요?","JPN":"しゃ、社長ですか？","ENG":"C-CEO?","TWN":"老、老闆？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흠. 자네들 얘기는 부사장을 통해 얼추 전해 들었네. 인터넷 방송인가를 하고 있다지.","JPN":"ふむ、君たちの話は副社長から大体聞いている。インターネット放送か何かをやっているそうだな。","ENG":"Hmm. The Vice President has told me about you lot. I hear you have your own show on the Internet or something.","TWN":"嗯哼，妳們的事情，我已經聽副總大致介紹過了。聽說妳們在做線上直播？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"훌륭해! 오늘을 시작으로 내 위업이 온 세상에 널리 알려지겠군!","JPN":"素晴らしい！　今日を起点に、私の偉業が全世界に知られるだろうな！","ENG":"Excellent! Now the whole world will come to know of my achievements!","TWN":"非常棒！從今天開始，我的偉業將傳遍到全世界！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼 우선 저기 있는 내 순금상부터 찍게. 이름은 머신 갓이니 자막도 예쁘게 입혀 주고.","JPN":"ではまず、あそこにある私の純金像から撮ってくれ。名前はマシーンゴッドだから、ちゃんと字幕も付けてな。","ENG":"Why don't you start by filming my golden statue over there? Its name is Machine God. Make sure you put in a nice caption too.","TWN":"那麼先從我的純金雕像開始拍吧。它叫機甲·皇級，拜託把這塊字幕弄得漂亮一點。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네? 네? 찍어야 하나요? 네?","JPN":"えっ？　はい？　撮るんですか？　え？","ENG":"Err, sorry? Do we have to film it? Really?","TWN":"咦？咦？要拍這個嗎？咦？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"암, 암. 놀랄 만도 하겠지. 회사 1년치 예산을 들여 만든 걸작이거든.","JPN":"まあまあ、そりゃ驚くだろうな。会社の1年分の予算を投入して作った傑作だから。","ENG":"Of course. And I understand why you'd be startled. I invested a year's worth of the company's finances to create that masterpiece.","TWN":"鏘，鏘。妳們聽了會嚇死吧，這可是用公司一年份的預算打造出的傑作。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"물론 그 정도 지출이야 내 위대함을 알리는 비용으로는 저렴한 편이지.","JPN":"まあ、私の偉大さを知らしめるための出費にしては安いほうだが。","ENG":"Which is a paltry sum considering how it's used to proclaim my greatness.","TWN":"當然，用這點程度支出來宣揚我的偉大之處，實在太便宜了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"1년치 뭐요......?","JPN":"1年分ですって……？","ENG":"A year's worth of what?!","TWN":"一年份的什麼……？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"지, 진정하게, 관리부장! 방송을 위한 조크야! 조크!","JPN":"お、落ち着きなさい、管理部長！　放送のためのジョークだ！　ジョーク！","ENG":"C-calm down, Manager Kim! It was a little joke for the show! A joke!","TWN":"冷、冷靜啊，管理部長！這是為了節目效果的開玩笑啊！玩笑！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으으...... 이나 언니가 이번엔 제대로 된 곳을 섭외해 주는 줄 알았는데......","JPN":"うう……メグミさんが今度こそちゃんとしたところを探してくれると思ったのに……","ENG":"Aw... I thought Ina had arranged for a normal company to shoot this time...","TWN":"嗚嗚……我還以為理娜姐會幫我們找個正常點的地方……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그, 그래도 가은아! 오늘 방송 둘이 열심히 해 보자!","JPN":"で、でもユキ！　今日の放送、二人で頑張ってみようよ！","ENG":"S-still, Gaeun? Let's see if we can make the most of this today!","TWN":"就、就算這樣，嘉恩！今天的直播就靠我們兩個好好加油吧！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"히익......! 왜, 왜 그래, 가은아...... 그런 무서운 표정 짓고...... 나 뭐 잘못했어......?","JPN":"ひい……！　ど、どうしたの、ユキ……そんな怖い顔して……私が何か悪いことでもした……？","ENG":"Eeep! W-w-what's wrong, Gaeun... You're making such a scary face... Did I do something to upset you?","TWN":"咿……！怎、怎麼了，嘉恩……露出那麼恐怖的表情……我做錯什麼了嗎……？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"가, 가은아! 어디 가! 잠깐만 기다려!","JPN":"ねえ、ユキ！　どこ行くの！　ちょっと待ってよ！","ENG":"G-Gaeun! Where are you going?! Wait!","TWN":"嘉、嘉恩！妳要去哪！等等我啊！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"안녕하세요, 가은입니다.","JPN":"こんにちは、ユキです。","ENG":"Hello, I'm Gaeun.","TWN":"您好，我是嘉恩。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 인사성이 바른 친구군. 나는 머신 갑일세.","JPN":"おお、礼儀正しい子だな。私はマシーン-甲-だ。","ENG":"Well, you're a polite little girl. I'm Machine G.A.P.","TWN":"哦，是位有禮貌的朋友呢，我是機械·我超帥~。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"실례지만 궁금한 게 있어요.","JPN":"失礼ですが、お聞きしたいことがあります。","ENG":"If I may, I'd like to ask you a question.","TWN":"不好意思，我有一個問題。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"예전에 그로니아라는 나라에 방문하신 적이 있지 않나요?","JPN":"以前、グロニアという国を訪れたことはありませんでしたか？","ENG":"Have you ever visited a country called Gronia in the past?","TWN":"您是不是曾經去過一個叫葛羅尼亞的國家？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......그, 그렇게 렌즈에 얼굴 들이밀진 말아 주겠나. 조금 부담스럽군.","JPN":"……そ、そんなにレンズに顔を近づけないでくれるかね。どうも気が引けてしまう。","ENG":"C-could you step back from my lens a little? You're making me a bit uncomfortable.","TWN":"……能、能不能不要把臉上貼在我的鏡頭上？我覺得有點壓力。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"죄송해요. 선생님.","JPN":"ごめんなさい、先生。","ENG":"Sorry. Teacher.","TWN":"對不起。老師。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"혹시 렌즈에 먼지가 묻어서 제 얼굴이 잘 안 보이실까 봐 확인해 봤어요.","JPN":"レンズにほこりが付いて、私の顔がよく見えないのかなと確認してみたんです。","ENG":"I thought you might have had trouble recognizing my face because of the dirt on the lens.","TWN":"我是怕鏡頭上有灰塵，讓您看不清我的臉，所以想確認一下。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠...... 잘 보이니까 걱정 말게나.","JPN":"ゴホン……よく見えているから心配することはない。","ENG":"Ahem... I can see just fine, so don't worry.","TWN":"嗯哼……我看得很清楚，不用擔心。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그보다 선생님이라니 무슨 뜻인지 모르겠군.","JPN":"ところで、先生とはどういうことなのか見当がつかないが。","ENG":"Anyway, I don't know why you'd call me a teacher.","TWN":"可是我不懂老師是什麼意思。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내 직함은 교사가 아니라 사장이라네. 다음부터는 사장님이라고 불러 주게.","JPN":"私の肩書きは教師ではなく社長だ。次からは社長って呼ぶように。","ENG":"I'm not an educator but a CEO of this company. You can just call me President.","TWN":"我的職稱不是老師，是老闆。下次開始叫我老闆吧。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런데 관리부장, 그로니아라는 곳이 어디지?","JPN":"ところで管理部長、グロニアとはどこなんだ？","ENG":"Anyway, where is this Gronia, Manager Kim?","TWN":"話說管理部長，那個叫葛羅尼亞的地方是哪裡啊？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 그로니아라면 20년간 내전 중인 동유럽의 작은 나라입니다.","JPN":"あ、グロニアなら20年間内戦が続いている東ヨーロッパの小さな国です。","ENG":"Oh, Gronia is a small country in Eastern Europe. It's been engulfed by civil war for the past 20 years.","TWN":"啊，葛羅尼亞是個持續了20多年內戰的東歐小國。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"한동안 관리국의 영향력도 미치지 못했던 드문 지역이죠.","JPN":"一時、管理局の影響力も及ばなかった珍しい地域です。","ENG":"It's one of the few countries that even the Administration couldn't influence for a while.","TWN":"有段時間，是個連管理局的影響力都無法到達的偏僻地區。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그것 참 불행한 일이로군.","JPN":"それは不幸なことだな。","ENG":"That sounds very unfortunate.","TWN":"那可真是不幸啊。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 나랑은 관계가 없는 일인 것 같은데.","JPN":"しかし、私とは何の関係もないことだと思うが。","ENG":"But it doesn't sound like I've got anything to do with that country.","TWN":"不過似乎跟我沒什麼關係呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내가 그런 복잡한 세상사와는 별로 인연이 없어서.","JPN":"私は複雑な世の中の出来事とは縁がなくてね。","ENG":"I usually stay away from the complicated affairs of international relations.","TWN":"我和那種複雜的世界沒什麼緣分。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"하지만 그로니아의 침식지대에서 절 구해 주셨죠.","JPN":"でもグロニアの侵食地帯で私を助けてくれました。","ENG":"But you did save me from the Corrupted Area in Gronia.","TWN":"可是您確實在葛羅尼亞的侵蝕地帶救了我。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠! 크흠! 크어흐음!","JPN":"ゴ、ゴホン！　ゴッホーン！","ENG":"Ahem! Ahem! Aheeeem!","TWN":"咳咳！咳咳！咳咳咳咳！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"가, 가은아. 사장님께서 곤란해 하시는 거 같은데......","JPN":"ちょっとユキ。社長さんが困ってるみたいだけど……","ENG":"G-Gaeun. I think you're putting the President on the spot here...","TWN":"嘉、嘉恩。老闆好像很困擾的樣子……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"기다려. 중요한 일이야.","JPN":"待って。大事なことだから。","ENG":"Wait. This is important.","TWN":"請等一下。這是很重要的事情。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"흐이잉......","JPN":"ふえーん……","ENG":"Wah...","TWN":"嗚嗚……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"모른 척하셔도 전 기억하고 있어요. 선생님을 따라다니면서 겪었던 일 전부요.","JPN":"知らないふりをしても私は覚えてるんです。先生について回りながら経験したこと全部。","ENG":"Even if you play the fool, I remember it all. Every little detail about what happened when I followed you around.","TWN":"即使您裝作不知道，我也記得很清楚，那些跟著老師經歷過的所有事情。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"선생님이 어디서 오셨는지도, 이름이 뭔지도, 얼굴이 어떻게 생겼는지도 모르지만......","JPN":"先生がどこから来たのか、名前は何か、どんな顔をしているのかもわかりませんが……","ENG":"I don't know where you're actually from, or your name, or even what you look like...","TWN":"雖然不知道老師是從哪裡來，叫什麼名字，長什麼樣子……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"로봇 뒤에 계셔도 전 알 수 있어요.","JPN":"ロボットの裏に隠れていても私にはわかるんです。","ENG":"I can tell it's you, even if you hide behind that robot.","TWN":"但就算您躲在機器人後面，我也認得出來。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"선생님의 다정한 목소리를 기억하고 있거든요.","JPN":"先生の優しい声を覚えていますから。","ENG":"Because I remember that gentle voice of yours.","TWN":"因為我記得老師溫柔的聲音。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이, 이보게. 이건 변조된 목소리인데 어떻게 알아듣는단 말인가?","JPN":"お、おい。これは変調された声なのに、どうやってわかるって言うんだ？","ENG":"H-hey now. This voice is modulated. There's no way you could recognize it.","TWN":"我，我說啊，我可是開著變聲器，妳是怎麼知道妳沒有認錯？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잘 들어보게, 이펙팅이 듬뿍 들어가지 않았나.","JPN":"よく聞いてみろ、エフェクトがたっぷりかかっているじゃないか。","ENG":"Listen carefully. There's a lot of special effects in there.","TWN":"仔細聽，是不是摻雜了很多雜音啊。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"상관없어요. 저는 알 수 있어요.","JPN":"そんなの関係ありません。私にはわかります。","ENG":"It doesn't matter. I can still tell.","TWN":"沒關係，我就是知道。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"선생님을 향한 제 마음은 사운드 이펙트 따위에 속지 않으니까요.","JPN":"先生への私の気持ちは、サウンドエフェクトなんかに騙されませんから。","ENG":"You can't fool my heart with just some lousy sound effects.","TWN":"我對老師的心意，是不會被區區聲效所欺騙的。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그게 말이 되나......?","JPN":"ほ、本気で言ってるのか……？","ENG":"I-is that even possible?","TWN":"有、有這種事……？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"카운터 능력이 이상한 쪽으로 발현된 것 같은데......","JPN":"カウンターの能力がおかしな方向で発現したようだが……","ENG":"Perhaps your Counter abilities have taken a rather unconventional turn...","TWN":"制裁者能力好像往奇怪的方向發展了啊……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님? 이게 다 무슨 이야기죠?","JPN":"社長？　いったい何のことですか？","ENG":"Boss? What is she talking about?","TWN":"老闆？這是怎麼回事？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"대체 예전에 무슨 일을 하고 다니셨길래......","JPN":"前にいったいどんなことをしていたら……","ENG":"What were you doing in the past?","TWN":"您以前到底做過什麼……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어흠! 어흠흠! 나, 난 잘 모르겠네! 아무튼 잘 몰라!","JPN":"ゴホン！　ゴホンホン！　わ、私はよくわからないな！　とにかく知らない！","ENG":"Ahem! Ahem, ahem! I-I have no idea! Absolutely no idea!","TWN":"咳咳！咳咳咳！我、我不太清楚呢！總之我不知道！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼 난 갑자기 급한 볼일이 생겨서 이만 실례!","JPN":"それでは、急ぎの用事ができたから先に失礼するぞ！","ENG":"Anyway, I've got an urgent errand to run, so bye now!","TWN":"我突然有點急事，失陪！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네?! 사장님, 촬영 중에 갑자기 그렇게 가 버리시면 곤란한데......!","JPN":"え！？　社長、撮影中にいきなりいなくなられては困るんですけど……！","ENG":"What?! You can't just bail like that during shooting!","TWN":"咦？！老闆，您直播的時候突然跑掉，我會很困擾的……！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"어쩌지...... 도망가 버리셨어.","JPN":"どうしよう……逃げちゃった。","ENG":"Oh no... The president is gone.","TWN":"怎麼辦……已經跑掉了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"죄송합니다. 보시다시피 저희 사장님께서 조금 당황하신 것 같네요.","JPN":"すみません。ご覧のとおり、うちの社長が少し戸惑ってしまったようでして。","ENG":"I'm sorry. It seems like my boss was a little startled.","TWN":"非常抱歉。大家也看到了，老闆似乎有些尷尬。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"원래는 함께 안내해 드릴 예정이었는데, 저 혼자 맡아야겠어요. 괜찮을까요?","JPN":"本当は一緒に案内するつもりだったのに、私一人でやるしかありませんね。大丈夫ですか？","ENG":"We were going to show you around together, but I guess it's just going to be me now. Is that okay?","TWN":"我們本來打算一起介紹的，現在只有我一個人了。這樣沒關係嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아, 네! 괜찮습니다! 오늘 하루 잘 부탁드릴게요!","JPN":"あっ、はい！　大丈夫です！　今日一日よろしくお願いします！","ENG":"Oh, sure! That's perfectly fine! Thank you in advance!","TWN":"啊，是的！沒關係！今天就請多多指教！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"휴우...... 큰 사고 없이 방송을 마무리해서 다행이야......","JPN":"ふう……無事に放送が終わってよかった……","ENG":"Whew... Thank goodness we managed to wrap that up without any huge incidents.","TWN":"呼……幸好直播時沒發生什麼大事故……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"가은아, 아까 왜 그랬어? 혹시 이나 언니가 따로 써 준 대본은 아니지? 응?","JPN":"ユキ、さっきはどうしたの？　まさかメグミさんが書いた台本とかじゃないよね？　ね？","ENG":"What was up with that earlier, Gaeun? Did Ina give you a separate script or something? Hm?","TWN":"嘉恩，妳剛才怎麼了？不會是理娜姐另外寫了劇本吧？嗯？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};